diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 76020d2b1dbf..bbc8b4158e37 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -7451,6 +7451,12 @@ Instruction *InstCombinerImpl::visitICmpInst(ICmpInst &I) {
     }
   }

+  // Try to fold icmp (trunc nuw/nsw X), (trunc nuw/nsw Y) before canonicalizing
+  // icmp on bool types. This allows us to fold icmp eq i1 (trunc nuw a), (trunc nuw b)
+  // to icmp eq i8 a, b instead of converting to xor first.
+  if (Instruction *Res = foldICmpTruncWithTruncOrExt(I, Q))
+    return Res;
+
   if (Op0->getType()->isIntOrIntVectorTy(1))
     if (Instruction *Res = canonicalizeICmpBool(I, Builder))
       return Res;
@@ -7473,9 +7479,6 @@ Instruction *InstCombinerImpl::visitICmpInst(ICmpInst &I) {
   if (Instruction *Res = foldICmpUsingKnownBits(I))
     return Res;

-  if (Instruction *Res = foldICmpTruncWithTruncOrExt(I, Q))
-    return Res;
-
   // Test if the ICmpInst instruction is used exclusively by a select as
   // part of a minimum or maximum operation. If so, refrain from doing
